package com.assetflow.nexora.entity;
import jakarta.persistence.*; import java.time.*; @Entity @Table(name="notifications") public class Notification { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="notification_id") public Long id; @Column(name="user_id",nullable=false) public Long userId; @Column(nullable=false,length=50) public String type; @Column(nullable=false,length=150) public String title; @Column(nullable=false,columnDefinition="text") public String message; @Column(name="related_entity_type",length=50) public String relatedEntityType; @Column(name="related_entity_id") public Long relatedEntityId; @Column(name="is_read",nullable=false) public boolean read; @Column(name="created_at",nullable=false) public OffsetDateTime createdAt; @PrePersist void created(){if(createdAt==null)createdAt=OffsetDateTime.now(ZoneOffset.UTC);} }
